// components/admin/ZapatillaForm.js
import React, { useState, useEffect } from "react";

export default function ZapatillaForm({ zapatilla, onSave }) {
  const [formData, setFormData] = useState({
    nombre: "",
    marca: "",
    precio: "",
    cantidad: "",
    imagen: "",
  });

  useEffect(() => {
    if (zapatilla) {
      setFormData(zapatilla);
    }
  }, [zapatilla]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(formData);
    setFormData({ nombre: "", marca: "", precio: "", cantidad: "", imagen: "" });
  };

  return (
    <form onSubmit={handleSubmit} className="mb-6 grid grid-cols-1 md:grid-cols-5 gap-4">
      <input
        type="text"
        name="nombre"
        value={formData.nombre}
        onChange={handleChange}
        placeholder="Nombre"
        className="border p-2 rounded"
        required
      />
      <input
        type="text"
        name="marca"
        value={formData.marca}
        onChange={handleChange}
        placeholder="Marca"
        className="border p-2 rounded"
        required
      />
      <input
        type="number"
        name="precio"
        value={formData.precio}
        onChange={handleChange}
        placeholder="Precio"
        className="border p-2 rounded"
        required
      />
      <input
        type="number"
        name="cantidad"
        value={formData.cantidad}
        onChange={handleChange}
        placeholder="Cantidad"
        className="border p-2 rounded"
        required
      />
      <input
        type="text"
        name="imagen"
        value={formData.imagen}
        onChange={handleChange}
        placeholder="URL Imagen"
        className="border p-2 rounded"
      />
      <button
        type="submit"
        className="bg-orange-500 text-white p-2 rounded col-span-1 md:col-span-5"
      >
        {zapatilla ? "Actualizar" : "Agregar"}
      </button>
    </form>
  );
}
